export const bookA1Cards: VocabCard[] = cardRows.map(
  ([deckId, frontFr, backEn, gender, exampleFr, exampleEn, tag], index) => ({
    id: `book-a1-card-${index + 1}`,
    deckId,
    frontFr,
    backEn,
    gender,
    exampleFr,
    exampleEn,
    tags: ['book-a1', tag],
    notes: 'Curated from Hachette A1 pages 116 to 119.',
    confidence: 0,
    dueAt: today,
    intervalDays: 1,
    difficulty: 1,
    source: 'seed',
  }),
)

const bookVerbOrder = [
  'être',
  'avoir',
  'aller',
  'faire',
  'aimer',
  'offrir',
  'appeler',
  'acheter',
  'préférer',
  'payer',
  'finir',
  'sortir',
  'voir',
  'vouloir',
]

export function applyBookA1TopicOverrides(topics: SkillTopic[]) {
  topics.forEach((topic) => {
    const override = topicOverrides[topic.id]
    if (override) Object.assign(topic, override)
  })
}

export function applyBookA1VerbOverrides(verbs: VerbEntry[]) {
  const orderMap = new Map(bookVerbOrder.map((infinitive, index) => [infinitive, index]))
  verbs.forEach((verb) => {
    const order = orderMap.get(verb.infinitive)
    if (order !== undefined) {
      verb.sequence = order + 1
      verb.difficulty = verb.infinitive === 'être' || verb.infinitive === 'avoir' ? 1 : 2
      verb.estimatedMinutes = 10
      verb.source = 'seed'
    }
  })
}
